SELECT ?album ?albumLabel WHERE {
  ?album wdt:P31 wd:Q386224;
         wdt:P175 wd:Q178095;
         wdt:P166 wd:Q265261;
         wdt:P166 wd:Q382052.
  ?album rdfs:label ?albumLabel.
  FILTER (LANGMATCHES(LANG(?albumLabel), 'en'))
}

SELECT ?album ?albumLabel WHERE {
  ?album wdt:P31 wd:Q386224;
         wdt:P175 wd:Q178095;
         wdt:P166 ?grammyAward.
  ?grammyAward rdfs:label ?grammyLabel.
  FILTER (LANGMATCHES(LANG(?grammyLabel), 'en') && CONTAINS(LCASE(?grammyLabel), 'grammy'))
  ?album wdt:P166 ?junoAward.
  ?junoAward rdfs:label ?junoLabel.
  FILTER (LANGMATCHES(LANG(?junoLabel), 'en') && CONTAINS(LCASE(?junoLabel), 'juno'))
  ?album rdfs:label ?albumLabel.
  FILTER (LANGMATCHES(LANG(?albumLabel), 'en'))
}

